// Append-only event store implementation

import { Event, RecordedSession } from './types';

export class EventStore {
  private events: Event[] = [];
  private sessions: Map<string, RecordedSession> = new Map();

  append(event: Event): void {
    this.events.push(event);
  }

  getSession(id: string): RecordedSession | undefined {
    return this.sessions.get(id);
  }

  getEventsInRange(start: number, end: number): Event[] {
    return this.events.filter(
      e => e.timestamp >= start && e.timestamp <= end
    );
  }

  createSession(serviceIds: string[]): RecordedSession {
    const session: RecordedSession = {
      id: crypto.randomUUID(),
      startTime: Date.now() * 1_000_000, // convert to nanoseconds
      endTime: 0,
      events: [],
      services: serviceIds
    };
    this.sessions.set(session.id, session);
    return session;
  }
}
