// Event recorder for distributed services

import { Event, RecordedSession } from './types';
import { EventStore } from './eventStore';

export class Recorder {
  private activeSessions: Set<string> = new Set();

  constructor(private store: EventStore) {}

  startRecording(serviceIds: string[]): RecordedSession {
    const session = this.store.createSession(serviceIds);
    this.activeSessions.add(session.id);
    return session;
  }

  recordEvent(sessionId: string, event: Event): void {
    if (!this.activeSessions.has(sessionId)) {
      throw new Error(`Session ${sessionId} is not active`);
    }
    this.store.append(event);
  }

  stopRecording(sessionId: string): void {
    this.activeSessions.delete(sessionId);
  }
}
