// HTTP and WebSocket server

import express, { Request, Response } from 'express';
import { WebSocketServer, WebSocket } from 'ws';
import { Recorder } from './recorder';
import { ReplayEngine } from './replay';
import { EventStore } from './eventStore';

export function createServer() {
  const app = express();
  app.use(express.json());

  const store = new EventStore();
  const recorder = new Recorder(store);
  const replayEngine = new ReplayEngine(store);

  // REST endpoints
  app.post('/api/sessions', (req: Request, res: Response) => {
    const { serviceIds } = req.body;
    const session = recorder.startRecording(serviceIds);
    res.json(session);
  });

  app.post('/api/sessions/:sessionId/events', (req: Request, res: Response) => {
    const event = req.body;
    recorder.recordEvent(req.params.sessionId, event);
    res.status(201).send();
  });

  app.post('/api/sessions/:sessionId/stop', (req: Request, res: Response) => {
    recorder.stopRecording(req.params.sessionId);
    res.status(200).send();
  });

  // WebSocket for real-time updates
  const wss = new WebSocketServer({ port: 8081 });
  wss.on('connection', (ws: WebSocket) => {
    ws.on('message', (data: string) => {
      // Handle real-time event streaming
    });
  });

  return app;
}
